#include <stdio.h>
#include <stdbool.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int prev, cur; bool sorted = true;
        scanf("%d", &prev);
        for(int i=1;i<N;i++){
            scanf("%d", &cur);
            if(prev>cur) sorted = false;
            prev = cur;
        }
        if(sorted){
            printf("YES\n0 0\n");
        }else{
            printf("YES\n1 1\n1 1 %d\n", N);
        }
    }
    return 0;
}

